#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=1000005;
ll t,n,a[N],m,dp[N][25];
vector<int> v[N];
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>t;
	v[0].push_back(1);
	while(t--)
	{
		cin>>n>>m;
		for(int i=1;i<=n;i++)
		{
			for(int j=0;j<22;j++) dp[i][j]=1e17;
			cin>>a[i];
			v[i].clear();
		}
		ll ans1=0,ans2=1e17;
		for(int i=1;i<=n;i++)
		{
			ll mx=a[i],tmp=a[i];
			for(int j=1;j<=10;j++)
			{
				tmp=m/tmp;
				mx=max(mx,tmp);
			}
			tmp=a[i];
			for(int j=1;j<=20;j++)
			{
				if(tmp==mx)
				{
					v[i].push_back(j);
				}
				tmp=m/tmp;
			}
			ans1+=mx;
		}
		dp[0][0]=0;
		cout<<ans1<<" ";
		for(int i=1;i<=n;i++)
		{
			for(int j=0;j<v[i].size();j++)
			{
				for(int k=0;k<v[i-1].size();k++)
				{
					dp[i][j]=min(dp[i][j],dp[i-1][k]+max(0,v[i][j]-v[i-1][k]));
				}
				if(i==n) ans2=min(ans2,dp[i][j]);
			}
		}
		cout<<ans2<<"\n";
	}
	return 0;
}
